import{_ as a,c as t,o as d,ag as r}from"./chunks/framework.dvv-DFtf.js";const p=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"memx/faq.md","filePath":"memx/faq.md","lastUpdated":1772252630000}'),i={name:"memx/faq.md"};function o(s,e,l,n,h,c){return d(),t("div",null,[...e[0]||(e[0]=[r(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /memx\\faq.md for this page in Markdown format</div><h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="基础问题" tabindex="-1">基础问题 <a class="header-anchor" href="#基础问题" aria-label="Permalink to &quot;基础问题&quot;">​</a></h2><h3 id="memx-和-mem0-是什么关系" tabindex="-1">MemX 和 mem0 是什么关系？ <a class="header-anchor" href="#memx-和-mem0-是什么关系" aria-label="Permalink to &quot;MemX 和 mem0 是什么关系？&quot;">​</a></h3><p>MemX 是在 <a href="https://github.com/mem0ai/mem0" target="_blank" rel="noreferrer">mem0</a> 基础上构建的增强版本，新增了 ACE（Adaptive Context Engine）智能记忆管理层。当 <code>ace_enabled=False</code> 时，MemX 与 mem0 的行为完全一致，零额外开销。你可以将 MemX 视为 mem0 的&quot;超集&quot;。</p><h3 id="需要-gpu-吗" tabindex="-1">需要 GPU 吗？ <a class="header-anchor" href="#需要-gpu-吗" aria-label="Permalink to &quot;需要 GPU 吗？&quot;">​</a></h3><p>不需要。MemX 的本地嵌入模型（all-MiniLM-L6-v2）通过 ONNX Runtime 在 CPU 上运行，推理速度 &lt; 5ms/条。知识提取（Reflector）的规则预筛选阶段不依赖 GPU，hybrid 模式下的 LLM 精炼通过远程 API 完成。</p><h3 id="会消耗额外的-llm-token-吗" tabindex="-1">会消耗额外的 LLM Token 吗？ <a class="header-anchor" href="#会消耗额外的-llm-token-吗" aria-label="Permalink to &quot;会消耗额外的 LLM Token 吗？&quot;">​</a></h3><p>默认的 <code>hybrid</code> 模式会对有价值的候选项调用 LLM 精炼，但由于规则预筛选过滤了大量低价值内容，实际 LLM 开销远低于 mem0 等全量调用方案（减少 90%+ 的调用）。如需完全零 LLM 调用，可将 <code>reflector.mode</code> 切换为 <code>&quot;rules&quot;</code> 模式。</p><h3 id="支持哪些向量数据库" tabindex="-1">支持哪些向量数据库？ <a class="header-anchor" href="#支持哪些向量数据库" aria-label="Permalink to &quot;支持哪些向量数据库？&quot;">​</a></h3><p>MemX 继承 mem0 的全部向量数据库支持，包括：Qdrant、Chroma、Pinecone、Weaviate、Milvus 等。默认使用内存向量存储，适合开发和测试。</p><h2 id="使用问题" tabindex="-1">使用问题 <a class="header-anchor" href="#使用问题" aria-label="Permalink to &quot;使用问题&quot;">​</a></h2><h3 id="如何从-mem0-迁移到-memx" tabindex="-1">如何从 mem0 迁移到 MemX？ <a class="header-anchor" href="#如何从-mem0-迁移到-memx" aria-label="Permalink to &quot;如何从 mem0 迁移到 MemX？&quot;">​</a></h3><ol><li>安装 MemX：<code>pip install git+https://github.com/UU114/memx.git</code></li><li>将 <code>from mem0 import Memory</code> 改为 <code>from memx import Memory</code></li><li>现有代码无需任何改动（ACE 默认关闭）</li><li>准备好后，添加 <code>config={&quot;ace_enabled&quot;: True}</code> 开启智能功能</li></ol><h3 id="知识库数据存在哪里" tabindex="-1">知识库数据存在哪里？ <a class="header-anchor" href="#知识库数据存在哪里" aria-label="Permalink to &quot;知识库数据存在哪里？&quot;">​</a></h3><p>取决于你配置的向量数据库后端。默认使用内存存储（重启后丢失）。生产环境建议使用 Qdrant 或 Chroma 等持久化后端。本地嵌入模型缓存在 <code>~/.memx/models/</code>。</p><h3 id="如何控制知识的衰减速度" tabindex="-1">如何控制知识的衰减速度？ <a class="header-anchor" href="#如何控制知识的衰减速度" aria-label="Permalink to &quot;如何控制知识的衰减速度？&quot;">​</a></h3><p>调整以下参数：</p><table tabindex="0"><thead><tr><th>参数</th><th>效果</th></tr></thead><tbody><tr><td><code>decay.half_life_days</code></td><td>增大 → 衰减更慢（默认 30 天）</td></tr><tr><td><code>decay.boost_factor</code></td><td>增大 → 召回增强更明显（默认 0.1）</td></tr><tr><td><code>decay.permanent_threshold</code></td><td>减小 → 更容易成为永久记忆（默认 15 次）</td></tr></tbody></table><h3 id="如何处理误判的知识" tabindex="-1">如何处理误判的知识？ <a class="header-anchor" href="#如何处理误判的知识" aria-label="Permalink to &quot;如何处理误判的知识？&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看所有知识</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">memx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --scope</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> project:my-app</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 删除错误的知识</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">memx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> forget</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">memory-i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 手动添加正确的知识</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">memx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> learn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;correct knowledge here&quot;</span></span></code></pre></div><h3 id="多人-多-agent-如何共享知识" tabindex="-1">多人/多 Agent 如何共享知识？ <a class="header-anchor" href="#多人-多-agent-如何共享知识" aria-label="Permalink to &quot;多人/多 Agent 如何共享知识？&quot;">​</a></h3><p>启用守护进程模式，多个 Agent 通过 IPC Socket 共享同一个知识库。适用于 IDE 插件、团队协作等场景。注意使用 <code>scope</code> 区分不同项目或工作区的知识。</p><h2 id="隐私问题" tabindex="-1">隐私问题 <a class="header-anchor" href="#隐私问题" aria-label="Permalink to &quot;隐私问题&quot;">​</a></h2><h3 id="隐私过滤可以关闭吗" tabindex="-1">隐私过滤可以关闭吗？ <a class="header-anchor" href="#隐私过滤可以关闭吗" aria-label="Permalink to &quot;隐私过滤可以关闭吗？&quot;">​</a></h3><p><strong>不可以</strong>。12 种内置的 PII 过滤规则是不可禁用的安全底线。你只能通过 <code>privacy_custom_patterns</code> 添加额外的过滤规则。</p><h3 id="支持哪些-pii-类型的过滤" tabindex="-1">支持哪些 PII 类型的过滤？ <a class="header-anchor" href="#支持哪些-pii-类型的过滤" aria-label="Permalink to &quot;支持哪些 PII 类型的过滤？&quot;">​</a></h3><table tabindex="0"><thead><tr><th>PII 类型</th><th>示例</th></tr></thead><tbody><tr><td>PEM 私钥</td><td><code>-----BEGIN RSA PRIVATE KEY-----</code></td></tr><tr><td>Bearer / JWT Token</td><td><code>Bearer eyJhbG...</code></td></tr><tr><td>Anthropic API Key</td><td><code>sk-ant-api03-*</code></td></tr><tr><td>OpenAI API Key</td><td><code>sk-proj-*</code></td></tr><tr><td>GitHub Token</td><td><code>ghp_*</code>, <code>github_pat_*</code></td></tr><tr><td>AWS Access Key</td><td><code>AKIA*</code></td></tr><tr><td>AWS Secret Key</td><td>40 字符 base64</td></tr><tr><td>数据库连接串</td><td><code>postgres://user:pass@host/db</code></td></tr><tr><td>操作系统路径</td><td><code>/home/user/.ssh/id_rsa</code></td></tr><tr><td>自定义规则</td><td>通过 <code>privacy_custom_patterns</code> 添加</td></tr></tbody></table><h3 id="过滤后的敏感信息去哪了" tabindex="-1">过滤后的敏感信息去哪了？ <a class="header-anchor" href="#过滤后的敏感信息去哪了" aria-label="Permalink to &quot;过滤后的敏感信息去哪了？&quot;">​</a></h3><p>敏感信息被替换为占位符（如 <code>[REDACTED:api_key]</code>），原始值不会被存储到任何地方。过滤在写入管道的最前端执行，确保敏感信息不会进入后续处理流程。</p><h2 id="性能问题" tabindex="-1">性能问题 <a class="header-anchor" href="#性能问题" aria-label="Permalink to &quot;性能问题&quot;">​</a></h2><h3 id="知识库能存多少条记忆" tabindex="-1">知识库能存多少条记忆？ <a class="header-anchor" href="#知识库能存多少条记忆" aria-label="Permalink to &quot;知识库能存多少条记忆？&quot;">​</a></h3><p>取决于向量数据库后端的容量。MemX 本身没有硬性限制。配合衰减引擎的自动归档机制，知识库会保持在合理的活跃规模。</p><h3 id="检索延迟是多少" tabindex="-1">检索延迟是多少？ <a class="header-anchor" href="#检索延迟是多少" aria-label="Permalink to &quot;检索延迟是多少？&quot;">​</a></h3><p>典型场景（&lt; 10,000 条记忆）：</p><table tabindex="0"><thead><tr><th>操作</th><th>延迟</th></tr></thead><tbody><tr><td>四层混合搜索</td><td>10-50ms</td></tr><tr><td>纯关键词搜索（L4 降级）</td><td>5-20ms</td></tr><tr><td>本地嵌入计算</td><td>&lt; 5ms</td></tr><tr><td>写入（含 Reflector + Curator）</td><td>20-100ms</td></tr></tbody></table><h3 id="recallreinforcer-会影响搜索性能吗" tabindex="-1">RecallReinforcer 会影响搜索性能吗？ <a class="header-anchor" href="#recallreinforcer-会影响搜索性能吗" aria-label="Permalink to &quot;RecallReinforcer 会影响搜索性能吗？&quot;">​</a></h3><p>不会。RecallReinforcer 在异步后台线程中运行，在返回搜索结果后才更新 <code>recall_count</code>，不阻塞搜索响应。</p>`,38)])])}const k=a(i,[["render",o]]);export{p as __pageData,k as default};
